using System.IO;
// using System.Collections.ObjectModel;
// using System.Diagnostics;
// using System.Net.Http;
// using System.Text;
// using System.Text.Json;
using System.Windows;
// using System.Windows.Input;
using System.Windows.Media.Media3D;
using TM12Viewer.Robot;

namespace TM12Viewer;

public partial class MainWindow : Window
{
    private readonly RobotModel _robotModel;
    private readonly TmRobotClient _client;

    // 갱신 주기 측정
    private DateTime _lastUpdateTime = DateTime.MinValue;
    private int _updateCount;
    private double _updateRate;

    // 축 값 TextBlock 배열
    private System.Windows.Controls.TextBlock[] _jointTexts = null!;
    private System.Windows.Controls.Primitives.RangeBase[] _jointBars = null!;

    public MainWindow()
    {
        InitializeComponent();

        // 축 값 UI 배열 초기화
        _jointTexts = [TxtJ1, TxtJ2, TxtJ3, TxtJ4, TxtJ5, TxtJ6];
        _jointBars = [BarJ1, BarJ2, BarJ3, BarJ4, BarJ5, BarJ6];

        // 로봇 3D 모델 초기화
        _robotModel = new RobotModel();
        Viewport3D.Children.Add(_robotModel.RootVisual);

        // TCP 클라이언트 초기화
        _client = new TmRobotClient();
        _client.DataReceived += OnDataReceived;
        _client.ConnectionChanged += OnConnectionChanged;
        _client.LogMessage += OnLogMessage;

        AddLog("TM12 Robot 3D Viewer 시작");

        // 창 로드 후 카메라 자동 설정
        Loaded += (_, _) => SetDefaultCamera();
    }

    /// <summary>
    /// 로봇 모델에 맞춰 카메라 설정 (베이스가 화면 하단에 오도록)
    /// </summary>
    private void SetDefaultCamera()
    {
        var cam = Viewport3D.Camera as PerspectiveCamera;
        if (cam == null) return;

        var target = new Point3D(0, 0, 400);
        var cameraPos = new Point3D(2200, -2200, 1400);

        cam.Position = cameraPos;
        cam.LookDirection = target - cameraPos;
        cam.UpDirection = new Vector3D(0, 0, 1);
        cam.FieldOfView = 45;

        Viewport3D.CameraController.CameraTarget = target;
    }

    /// <summary>
    /// 연결 버튼
    /// </summary>
    private async void BtnConnect_Click(object sender, RoutedEventArgs e)
    {
        _client.Host = TxtIp.Text.Trim();
        if (int.TryParse(TxtPort.Text.Trim(), out int port))
            _client.Port = port;

        BtnConnect.IsEnabled = false;
        await _client.ConnectAsync();
    }

    /// <summary>
    /// 해제 버튼
    /// </summary>
    private void BtnDisconnect_Click(object sender, RoutedEventArgs e)
    {
        _client.Disconnect();
    }

    /// <summary>
    /// 데이터 수신 이벤트 (백그라운드 스레드에서 호출)
    /// </summary>
    private void OnDataReceived(double[] jointAngles, double[] tcpCoord)
    {
        Dispatcher.Invoke(() =>
        {
            // 3D 모델 업데이트
            _robotModel.SetAllJointAngles(jointAngles);

            // 축 각도 UI 업데이트
            for (int i = 0; i < 6; i++)
            {
                _jointTexts[i].Text = $"{jointAngles[i]:F3}°";
                _jointBars[i].Value = jointAngles[i];
            }

            // TCP 좌표 UI 업데이트
            TxtTcpX.Text = $"{tcpCoord[0]:F3} mm";
            TxtTcpY.Text = $"{tcpCoord[1]:F3} mm";
            TxtTcpZ.Text = $"{tcpCoord[2]:F3} mm";
            TxtTcpRx.Text = $"{tcpCoord[3]:F3}°";
            TxtTcpRy.Text = $"{tcpCoord[4]:F3}°";
            TxtTcpRz.Text = $"{tcpCoord[5]:F3}°";

            // 갱신 주기 계산
            _updateCount++;
            var now = DateTime.Now;
            var elapsed = (now - _lastUpdateTime).TotalSeconds;
            if (elapsed >= 1.0)
            {
                _updateRate = _updateCount / elapsed;
                TxtUpdateRate.Text = $"갱신: {_updateRate:F1} Hz";
                _updateCount = 0;
                _lastUpdateTime = now;
            }
        });
    }

    /// <summary>
    /// 연결 상태 변경 이벤트
    /// </summary>
    private void OnConnectionChanged(bool connected, string message)
    {
        Dispatcher.Invoke(() =>
        {
            if (connected)
            {
                TxtStatus.Text = "연결됨";
                TxtStatus.Foreground = new System.Windows.Media.SolidColorBrush(
                    System.Windows.Media.Color.FromRgb(0x90, 0xC0, 0x90));
                TxtEndpoint.Text = message;
                BtnConnect.IsEnabled = false;
                BtnDisconnect.IsEnabled = true;
                _lastUpdateTime = DateTime.Now;
                _updateCount = 0;
            }
            else
            {
                TxtStatus.Text = "미연결";
                TxtStatus.Foreground = new System.Windows.Media.SolidColorBrush(
                    System.Windows.Media.Color.FromRgb(0x90, 0x90, 0x90));
                TxtEndpoint.Text = "-";
                TxtUpdateRate.Text = "갱신: -";
                BtnConnect.IsEnabled = true;
                BtnDisconnect.IsEnabled = false;
            }
        });
    }

    /// <summary>
    /// 로그 메시지 이벤트
    /// </summary>
    private void OnLogMessage(string message)
    {
        Dispatcher.Invoke(() => AddLog(message));
    }

    // 로그 파일 경로
    private static readonly string LogFilePath = Path.Combine(
        AppDomain.CurrentDomain.BaseDirectory, "app.log");

    /// <summary>
    /// 로그 추가 (UI + 파일)
    /// </summary>
    private void AddLog(string message)
    {
        var entry = $"[{DateTime.Now:HH:mm:ss.fff}] {message}";
        LstLog.Items.Add(entry);

        // 최대 500개 유지
        while (LstLog.Items.Count > 500)
            LstLog.Items.RemoveAt(0);

        // 자동 스크롤
        LstLog.ScrollIntoView(LstLog.Items[^1]);

        // 파일 기록
        try { File.AppendAllText(LogFilePath, entry + Environment.NewLine); }
        catch { /* 무시 */ }
    }

    /// <summary>
    /// 창 닫기
    /// </summary>
    private void Window_Closing(object sender, System.ComponentModel.CancelEventArgs e)
    {
        _client.Dispose();
    }

    #region 비상정지

    /// <summary>
    /// 비상정지 버튼 클릭
    /// </summary>
    private async void BtnEmergencyStop_Click(object sender, RoutedEventArgs e)
    {
        AddLog("[비상정지] 실행! (StopAndClearBuffer)");

        BtnEmergencyStop.IsEnabled = false;
        BtnEmergencyStop.Content = "정지 중...";

        try
        {
            var result = await _client.SendStopAsync();
            AddLog($"[비상정지] Stop 결과: {result.TrimEnd()}");
        }
        catch (Exception ex)
        {
            AddLog($"[비상정지] 오류: {ex.Message}");
        }
        finally
        {
            BtnEmergencyStop.IsEnabled = true;
            BtnEmergencyStop.Content = "\u26A0 비상정지";
        }
    }

    #endregion

    #region 채팅 (비활성 - 추후 복원)
    /*
    // === 채팅 관련 필드 ===
    // private readonly ObservableCollection<ChatMessage> _chatMessages = [];
    // private CancellationTokenSource? _chatCts;
    // private bool _isChatBusy;
    // private Process? _agentProcess;
    // private static readonly HttpClient _httpClient = new() { Timeout = TimeSpan.FromMinutes(5) };
    // private const string AgentUrl = "http://localhost:3100";
    // private double[] _latestJoints = new double[6];
    // private double[] _latestTcp = new double[6];
    // private static readonly string AgentDir = Path.GetFullPath(
    //     Path.Combine(AppDomain.CurrentDomain.BaseDirectory, "..", "..", "..", "..", "tm-agent"));

    // === ChatMessage 모델 ===
    // public class ChatMessage : System.ComponentModel.INotifyPropertyChanged
    // {
    //     private string _text = "";
    //     public string Text
    //     {
    //         get => _text;
    //         set { _text = value; PropertyChanged?.Invoke(this, new(nameof(Text))); }
    //     }
    //     public bool IsUser { get; set; }
    //     public event System.ComponentModel.PropertyChangedEventHandler? PropertyChanged;
    // }

    // === 생성자에서 추가할 코드 ===
    // LstChat.ItemsSource = _chatMessages;
    // StartAgentProcess();

    // === tm-agent 프로세스 시작 ===
    // private void StartAgentProcess() { ... }

    // === 채팅 메시지 전송 ===
    // private void BtnSend_Click(object sender, RoutedEventArgs e) => SendChatMessage();
    // private void TxtChatInput_KeyDown(object sender, KeyEventArgs e) { ... }
    // private async void SendChatMessage() { ... }
    // private async Task CallAgentAsync(string userInput, ChatMessage aiMessage, CancellationToken ct) { ... }
    // private void SetChatBusy(bool busy) { ... }
    // private void RefreshChatItem(ChatMessage msg) { ... }
    // private void ScrollChatToEnd() { ... }

    // === Window_Closing에 추가할 코드 ===
    // _chatCts?.Cancel();
    // if (_agentProcess != null && !_agentProcess.HasExited)
    //     try { _agentProcess.Kill(entireProcessTree: true); } catch { }

    // === 비상정지에 추가할 코드 ===
