285→    /// <summary>
286→    /// OnRobot Screwdriver 임시 형상 생성 (308 x 86 x 114mm)
287→    /// 플랜지 기준 Z축 방향으로 본체 + 비트
288→    /// </summary>
289→    private static ModelVisual3D CreateScrewdriverVisual()
290→    {
291→        var screwdriver = new ModelVisual3D();
292→
293→        // 스크류드라이버 재질 (진한 파란색)
294→        var bodyMat = new MaterialGroup();
295→        bodyMat.Children.Add(new DiffuseMaterial(new SolidColorBrush(Color.FromRgb(40, 60, 120))));
296→        bodyMat.Children.Add(new SpecularMaterial(new SolidColorBrush(Color.FromRgb(80, 80, 80)), 40));
297→
298→        // 비트 재질 (은색)
299→        var bitMat = new MaterialGroup();
300→        bitMat.Children.Add(new DiffuseMaterial(new SolidColorBrush(Color.FromRgb(180, 180, 190))));
301→        bitMat.Children.Add(new SpecularMaterial(new SolidColorBrush(Color.FromRgb(120, 120, 120)), 60));
302→
303→        // 본체: 플랜지 어댑터 (직경 86mm, 높이 30mm)
304→        screwdriver.Children.Add(new ModelVisual3D
305→        {
306→            Content = new GeometryModel3D(BuildCylinder(43, 0, 30, 24), bodyMat) { BackMaterial = bodyMat }
307→        });
308→        // 본체: 메인 바디 (직경 80mm, 높이 200mm)
309→        screwdriver.Children.Add(new ModelVisual3D
310→        {
311→            Content = new GeometryModel3D(BuildCylinder(40, 30, 230, 24), bodyMat) { BackMaterial = bodyMat }
312→        });
313→        // 본체: 선단부 테이퍼 (직경 50mm, 높이 40mm)
314→        screwdriver.Children.Add(new ModelVisual3D
315→        {
316→            Content = new GeometryModel3D(BuildCylinder(25, 230, 270, 24), bodyMat) { BackMaterial = bodyMat }
317→        });
318→        // 비트: 가는 원통 (직경 8mm, 길이 38mm)
319→        screwdriver.Children.Add(new ModelVisual3D
320→        {
321→            Content = new GeometryModel3D(BuildCylinder(4, 270, 308, 12), bitMat) { BackMaterial = bitMat }
322→        });
323→
324→        return screwdriver;
325→    }
326→
327→    /// <summary>
328→    /// Z축 방향 원통 메시 생성 (중심 0,0, 반지름 r, z0~z1)
329→    /// </summary>
330→    private static MeshGeometry3D BuildCylinder(double radius, double z0, double z1, int segments)
331→    {
332→        var mesh = new MeshGeometry3D();
333→        var positions = mesh.Positions;
334→        var indices = mesh.TriangleIndices;
335→
336→        // 상단/하단 원 정점 생성
337→        for (int i = 0; i < segments; i++)
338→        {
339→            double angle = 2 * Math.PI * i / segments;
340→            double x = radius * Math.Cos(angle);
341→            double y = radius * Math.Sin(angle);
342→            positions.Add(new Point3D(x, y, z0)); // 하단
343→            positions.Add(new Point3D(x, y, z1)); // 상단
344→        }
345→
346→        // 측면 삼각형
347→        for (int i = 0; i < segments; i++)
348→        {
349→            int next = (i + 1) % segments;
350→            int b0 = i * 2, t0 = i * 2 + 1;
351→            int b1 = next * 2, t1 = next * 2 + 1;
352→            indices.Add(b0); indices.Add(b1); indices.Add(t1);
353→            indices.Add(b0); indices.Add(t1); indices.Add(t0);
354→        }
355→
356→        // 상단/하단 캡 중심점
357→        int centerBottom = positions.Count;
358→        positions.Add(new Point3D(0, 0, z0));
359→        int centerTop = positions.Count;
360→        positions.Add(new Point3D(0, 0, z1));
361→
362→        for (int i = 0; i < segments; i++)
363→        {
364→            int next = (i + 1) % segments;
365→            // 하단 캡
366→            indices.Add(centerBottom); indices.Add(next * 2); indices.Add(i * 2);
367→            // 상단 캡
368→            indices.Add(centerTop); indices.Add(i * 2 + 1); indices.Add(next * 2 + 1);
369→        }
370→
371→        return mesh;
372→    }
373→
374→    /// <summary>
375→    /// 로봇 재질 생성 (밝은 회색 + 반사)
376→    /// </summary>
377→    private static MaterialGroup CreateMaterial()
378→    {
379→        var materialGroup = new MaterialGroup();
380→        materialGroup.Children.Add(new DiffuseMaterial(new SolidColorBrush(Color.FromRgb(200, 200, 210))));
381→        materialGroup.Children.Add(new SpecularMaterial(new SolidColorBrush(Color.FromRgb(100, 100, 100)), 50));
382→        return materialGroup;
383→    }
384→}
