using System.IO;
using System.Net.Sockets;
using System.Text;
using System.Text.Json;

namespace TM12Viewer.Robot;

/// <summary>
/// TM Robot Ethernet Slave (TMSVR) TCP 통신 클라이언트.
/// 포트 5891로 접속하여 관절 각도 및 TCP 좌표를 수신.
/// </summary>
public class TmRobotClient : IDisposable
{
    private TcpClient? _tcp;
    private NetworkStream? _stream;
    private CancellationTokenSource? _cts;
    private Task? _receiveTask;
    private readonly StringBuilder _recvBuffer = new();
    private readonly string _rawLogPath = Path.Combine(AppDomain.CurrentDomain.BaseDirectory, "raw_recv.log");
    private const long RAW_LOG_MAX_BYTES = 10 * 1024 * 1024; // 10MB 제한

    // TMSCT 비상정지용
    private int _sctCmdId;

    private bool _isConnected;

    public string Host { get; set; } = "192.168.1.50";
    public int Port { get; set; } = 5891;
    public bool IsConnected => _isConnected;

    /// <summary>
    /// 관절 각도(J1~J6, 도) + TCP 좌표(X,Y,Z,Rx,Ry,Rz) 수신 이벤트
    /// </summary>
    public event Action<double[], double[]>? DataReceived;

    /// <summary>
    /// 연결 상태 변경 이벤트
    /// </summary>
    public event Action<bool, string>? ConnectionChanged;

    /// <summary>
    /// 로그 이벤트
    /// </summary>
    public event Action<string>? LogMessage;

    /// <summary>
    /// 로봇에 연결
    /// </summary>
    public async Task ConnectAsync()
    {
        try
        {
            Disconnect();

            _tcp = new TcpClient();
            _tcp.ReceiveTimeout = 5000;
            _tcp.SendTimeout = 5000;

            LogMessage?.Invoke($"연결 시도: {Host}:{Port}");
            await _tcp.ConnectAsync(Host, Port);

            _stream = _tcp.GetStream();
            _recvBuffer.Clear();
            _isConnected = true;

            LogMessage?.Invoke($"연결 성공: {Host}:{Port}");
            ConnectionChanged?.Invoke(true, $"{Host}:{Port}");

            // 수신 루프 시작
            _cts = new CancellationTokenSource();
            _receiveTask = Task.Run(() => ReceiveLoop(_cts.Token));
        }
        catch (Exception ex)
        {
            LogMessage?.Invoke($"연결 실패: {ex.Message}");
            // 리소스만 정리, Disconnect 내부 이벤트 중복 방지
            CleanupResources();
            ConnectionChanged?.Invoke(false, ex.Message);
        }
    }

    /// <summary>
    /// 연결 해제
    /// </summary>
    public void Disconnect()
    {
        var wasConnected = _isConnected;
        CleanupResources();
        if (wasConnected)
            ConnectionChanged?.Invoke(false, "연결 해제");
    }

    /// <summary>
    /// TCP 리소스 정리 (이벤트 발사 없음)
    /// </summary>
    private void CleanupResources()
    {
        _isConnected = false;
        try
        {
            _cts?.Cancel();
            _stream?.Close();
            _tcp?.Close();
        }
        catch { }
        finally
        {
            _stream = null;
            _tcp = null;
            _cts = null;
            _receiveTask = null;
            _recvBuffer.Clear();
        }
    }

    /// <summary>
    /// 비동기 수신 루프
    /// </summary>
    private async Task ReceiveLoop(CancellationToken token)
    {
        var buffer = new byte[4096];

        try
        {
            while (!token.IsCancellationRequested && _stream != null)
            {
                int bytesRead = await _stream.ReadAsync(buffer, 0, buffer.Length, token);
                if (bytesRead == 0)
                {
                    LogMessage?.Invoke("서버가 연결을 종료했습니다.");
                    break;
                }

                var received = Encoding.ASCII.GetString(buffer, 0, bytesRead);
                try
                {
                    // 로그 크기 제한: 10MB 초과 시 삭제 후 재시작
                    if (File.Exists(_rawLogPath) && new FileInfo(_rawLogPath).Length > RAW_LOG_MAX_BYTES)
                        File.Delete(_rawLogPath);
                    File.AppendAllText(_rawLogPath, $"[{DateTime.Now:HH:mm:ss.fff}] {received}\n---\n");
                }
                catch { }
                _recvBuffer.Append(received);

                // 완성된 패킷 처리
                ProcessBuffer();
            }
        }
        catch (OperationCanceledException) { }
        catch (Exception ex)
        {
            if (!token.IsCancellationRequested)
                LogMessage?.Invoke($"수신 오류: {ex.Message}");
        }

        if (_isConnected)
        {
            _isConnected = false;
            ConnectionChanged?.Invoke(false, "연결 종료");
        }
    }

    /// <summary>
    /// 버퍼에서 완성된 TMSVR 패킷 추출 및 처리
    /// 패킷 포맷: $TMSVR,length,mode,transaction_id,JSON_data,*XX\r\n
    /// </summary>
    private void ProcessBuffer()
    {
        var buf = _recvBuffer.ToString();

        while (true)
        {
            // $TMSVR 헤더 찾기
            int headerIdx = buf.IndexOf("$TMSVR", StringComparison.Ordinal);
            if (headerIdx < 0)
            {
                _recvBuffer.Clear();
                return;
            }

            // 헤더 앞의 쓰레기 데이터 제거
            if (headerIdx > 0)
                buf = buf[headerIdx..];

            // 패킷 끝 찾기: ,*XX 패턴 (쉼표 + 별표 + HEX 2자리)
            int endIdx = FindPacketEnd(buf);
            if (endIdx < 0)
                break; // 아직 패킷 미완성

            var packet = buf[..endIdx];
            buf = buf[endIdx..];
            ParseTmsvrPacket(packet);
        }

        // 남은 데이터를 버퍼에 보존
        _recvBuffer.Clear();
        _recvBuffer.Append(buf);
    }

    /// <summary>
    /// ,*XX (체크섬) 패턴을 찾아 패킷 끝 인덱스 반환.
    /// JSON 내부의 * 문자와 혼동 방지: ,*[0-9A-Fa-f]{2} 뒤에 \r\n 또는 $ 또는 끝이 오는지 확인.
    /// </summary>
    private static int FindPacketEnd(string buf)
    {
        int searchFrom = 6; // $TMSVR 최소 길이 이후부터
        while (searchFrom < buf.Length)
        {
            int starIdx = buf.IndexOf(",*", searchFrom, StringComparison.Ordinal);
            if (starIdx < 0) return -1;

            // ,* 뒤에 HEX 2자리가 있는지 확인
            if (starIdx + 4 <= buf.Length)
            {
                char h1 = buf[starIdx + 2];
                char h2 = buf[starIdx + 3];
                if (IsHexChar(h1) && IsHexChar(h2))
                {
                    int endIdx = starIdx + 4;
                    // \r\n 스킵
                    if (endIdx < buf.Length && buf[endIdx] == '\r') endIdx++;
                    if (endIdx < buf.Length && buf[endIdx] == '\n') endIdx++;
                    return endIdx;
                }
            }
            searchFrom = starIdx + 1;
        }
        return -1;
    }

    private static bool IsHexChar(char c) =>
        (c >= '0' && c <= '9') || (c >= 'A' && c <= 'F') || (c >= 'a' && c <= 'f');

    /// <summary>
    /// TMSVR 패킷 파싱
    /// 예: $TMSVR,228,0,3,[{"Item":"Joint_Angle","Value":[...]},...],*2E
    /// </summary>
    private void ParseTmsvrPacket(string packet)
    {
        try
        {
            // $TMSVR,length,mode,transaction_id, 이후 JSON 부분 추출
            // 쉼표 4개를 건너뛰면 JSON 시작
            int commaCount = 0;
            int jsonStart = -1;
            for (int i = 0; i < packet.Length; i++)
            {
                if (packet[i] == ',')
                {
                    commaCount++;
                    if (commaCount == 4)
                    {
                        jsonStart = i + 1;
                        break;
                    }
                }
            }

            if (jsonStart < 0) return;

            // JSON 끝: ,*XX 패턴 찾기 (끝에서 역방향)
            int checksumIdx = packet.LastIndexOf(",*", StringComparison.Ordinal);
            if (checksumIdx < jsonStart) return;

            var jsonStr = packet[jsonStart..checksumIdx];

            // JSON 파싱
            var items = JsonSerializer.Deserialize<JsonElement[]>(jsonStr);
            if (items == null) return;

            double[]? jointAngles = null;
            double[]? tcpCoord = null;

            foreach (var item in items)
            {
                var itemName = item.GetProperty("Item").GetString();
                var value = item.GetProperty("Value");

                if (itemName == "Joint_Angle" && value.ValueKind == JsonValueKind.Array)
                {
                    jointAngles = new double[6];
                    for (int i = 0; i < Math.Min(value.GetArrayLength(), 6); i++)
                        jointAngles[i] = value[i].GetDouble();
                }
                else if ((itemName == "Coord_Base_Tool" || itemName == "Coord_Robot_Tool")
                         && value.ValueKind == JsonValueKind.Array)
                {
                    tcpCoord = new double[6];
                    for (int i = 0; i < Math.Min(value.GetArrayLength(), 6); i++)
                        tcpCoord[i] = value[i].GetDouble();
                }
            }

            if (jointAngles != null)
                DataReceived?.Invoke(jointAngles, tcpCoord ?? new double[6]);
        }
        catch (Exception ex)
        {
            LogMessage?.Invoke($"패킷 파싱 오류: {ex.Message}");
        }
    }

    #region TMSCT 비상정지

    /// <summary>
    /// TMSCT(5890)로 Pause 명령 전송 (일시정지, Listen Node 유지)
    /// </summary>
    public async Task<string> SendPauseAsync()
    {
        return await SendTmsctScriptAsync("Pause()");
    }

    /// <summary>
    /// TMSCT(5890)로 Resume 명령 전송
    /// </summary>
    public async Task<string> SendResumeAsync()
    {
        return await SendTmsctScriptAsync("Resume()");
    }

    /// <summary>
    /// TMSCT(5890)로 Stop 명령 전송 (완전 정지, Listen Node 종료됨 주의)
    /// </summary>
    public async Task<string> SendStopAsync()
    {
        return await SendTmsctScriptAsync("StopAndClearBuffer()");
    }

    /// <summary>
    /// TMSCT 포트(5890)에 일회성 연결 → 스크립트 전송 → 응답 수신 → 연결 종료
    /// MCP 서버와 포트 충돌 방지를 위해 일회성 연결 사용
    /// </summary>
    private async Task<string> SendTmsctScriptAsync(string script)
    {
        TcpClient? sctTcp = null;
        try
        {
            sctTcp = new TcpClient { SendTimeout = 3000, ReceiveTimeout = 3000 };
            await sctTcp.ConnectAsync(Host, 5890);

            var stream = sctTcp.GetStream();
            var id = (++_sctCmdId).ToString("D2");
            var packet = BuildTmsctPacket(id, script);

            LogMessage?.Invoke($"[TMSCT] 전송: {packet.TrimEnd()}");

            var bytes = Encoding.ASCII.GetBytes(packet);
            await stream.WriteAsync(bytes);

            // 응답 수신 (최대 3초)
            var buf = new byte[1024];
            var readTask = stream.ReadAsync(buf, 0, buf.Length);
            if (await Task.WhenAny(readTask, Task.Delay(3000)) == readTask)
            {
                int n = readTask.Result;
                var response = Encoding.ASCII.GetString(buf, 0, n);
                LogMessage?.Invoke($"[TMSCT] 응답: {response.TrimEnd()}");
                return response;
            }
            else
            {
                LogMessage?.Invoke("[TMSCT] 응답 타임아웃");
                return "TIMEOUT";
            }
        }
        catch (Exception ex)
        {
            LogMessage?.Invoke($"[TMSCT] 오류: {ex.Message}");
            return $"ERROR: {ex.Message}";
        }
        finally
        {
            try { sctTcp?.Close(); } catch { }
        }
    }

    /// <summary>
    /// TMSCT 패킷 생성: $TMSCT,{len},{id},{script},*{checksum}\r\n
    /// </summary>
    private static string BuildTmsctPacket(string id, string script)
    {
        var data = $"{id},{script}";
        var length = Encoding.ASCII.GetByteCount(data);
        var body = $"TMSCT,{length},{data},";
        var checksum = CalcChecksum(body);
        return $"${body}*{checksum}\r\n";
    }

    /// <summary>
    /// XOR 체크섬 ($ 제외, * 직전까지)
    /// </summary>
    private static string CalcChecksum(string content)
    {
        int xor = 0;
        foreach (char c in content)
            xor ^= c;
        return xor.ToString("X2");
    }

    #endregion

    public void Dispose()
    {
        Disconnect();
        GC.SuppressFinalize(this);
    }
}

