  3→import { McpServer } from '@modelcontextprotocol/sdk/server/mcp.js';
  4→import { z } from 'zod';
  5→import { TmClient } from './tm-client';
  6→
  7→const client = new TmClient();
  8→
  9→export function createServer(): McpServer {
