 11→    name: 'tm-robot',
 12→    version: '1.0.0',
 13→  });
 14→
 15→  // ===== 연결 관리 =====
 16→
 17→  server.tool(
 18→    'tm_connect',
 19→    '로봇 연결 (TMSCT 5890 + TMSVR 5891)',
