 68→    'tm_pause',
 69→    '로봇 일시정지',
 70→    {},
 71→    async () => {
 72→      const res = await client.pause();
 73→      return { content: [{ type: 'text' as const, text: `[${res.status}] ${res.message || res.id}` }] };
 74→    }
 75→  );
 76→
 77→  server.tool(
 78→    'tm_resume',
 79→    '로봇 재개',
 80→    {},
 81→    async () => {
 82→      const res = await client.resume();
 83→      return { content: [{ type: 'text' as const, text: `[${res.status}] ${res.message || res.id}` }] };
 84→    }
 85→  );
 86→
 87→  server.tool(
 88→    'tm_stop',
 89→    '로봇 정지 (Listen Node 종료됨 주의)',
 90→    {},
 91→    async () => {
 92→      const res = await client.stop();
 93→      return { content: [{ type: 'text' as const, text: `[${res.status}] ${res.message || res.id}\n⚠️ Listen Node가 종료되었을 수 있습니다.` }] };
 94→    }
 95→  );
 96→
 97→  server.tool(
