 99→    'Listen Node 탈출 (다음 노드로 진행)',
100→    {},
101→    async () => {
102→      const res = await client.scriptExit();
103→      return { content: [{ type: 'text' as const, text: `[${res.status}] ${res.message || res.id}` }] };
