114→    },
115→    async ({ script }) => {
116→      const res = await client.sendScript(script);
117→      return { content: [{ type: 'text' as const, text: `[${res.status}] ${res.message}\nID: ${res.id}\nRaw: ${res.raw}` }] };
118→    }
