145→      return { content: [{ type: 'text' as const, text: `AO${pin} → ${value}: [${res.status}] ${res.message || 'OK'}` }] };
146→    }
147→  );
148→
149→  server.tool(
150→    'tm_get_io',
151→    'IO 상태 조회 (DI/DO/AI/AO)',
152→    {},
153→    async () => {
154→      const res = await client.getIO();
155→      return { content: [{ type: 'text' as const, text: res.data }] };
156→    }
157→  );
158→
159→  // ===== 모션 제어 =====
