166→      j2: z.number().describe('J2 각도 (도)'),
167→      j3: z.number().describe('J3 각도 (도)'),
168→      j4: z.number().describe('J4 각도 (도)'),
169→      j5: z.number().describe('J5 각도 (도)'),
170→      j6: z.number().describe('J6 각도 (도)'),
171→      speed: z.number().optional().default(10).describe('속도 (%, 기본 10)'),
172→      acc: z.number().optional().default(200).describe('가속시간 (ms, 기본 200)'),
173→    },
174→    async ({ j1, j2, j3, j4, j5, j6, speed, acc }) => {
175→      const res = await client.movePtpJ([j1, j2, j3, j4, j5, j6], speed, acc);
176→      return { content: [{ type: 'text' as const, text: `PTP_J → [${res.status}] ${res.message || '이동 완료'}` }] };
177→    }
178→  );
179→
180→  server.tool(
181→    'tm_move_ptp_t',
182→    'PTP 직교 이동 (TCP)',
183→    {
184→      x: z.number().describe('X (mm)'),
185→      y: z.number().describe('Y (mm)'),
186→      z: z.number().describe('Z (mm)'),
187→      rx: z.number().describe('Rx (도)'),
