// MCP 서버 + TM Robot 도구 등록

import { McpServer } from '@modelcontextprotocol/sdk/server/mcp.js';
import { z } from 'zod';
import { TmClient } from './tm-client';

const client = new TmClient();

export function createServer(): McpServer {
  const server = new McpServer({
    name: 'tm-robot',
    version: '1.0.0',
  });

  // ===== 연결 관리 =====

  server.tool(
    'tm_connect',
    '로봇 연결 (TMSCT 5890 + TMSVR 5891)',
    {
      host: z.string().describe('로봇 IP 주소'),
      sctPort: z.number().optional().describe('TMSCT 포트 (기본 5890)'),
      svrPort: z.number().optional().describe('TMSVR 포트 (기본 5891)'),
    },
    async ({ host, sctPort, svrPort }) => {
      const result = await client.connect(host, sctPort, svrPort);
      return { content: [{ type: 'text' as const, text: result }] };
    }
  );

  server.tool(
    'tm_disconnect',
    '로봇 연결 해제',
    {},
    async () => {
      const result = client.disconnect();
      return { content: [{ type: 'text' as const, text: result }] };
    }
  );

  server.tool(
    'tm_status',
    '연결 상태 + 로봇 상태 조회',
    {},
    async () => {
      const info = client.getStatus();
      let text = `호스트: ${info.host || '(미연결)'}\n`;
      text += `TMSCT(${info.sctPort}): ${info.sctConnected ? '연결됨' : '미연결'}\n`;
      text += `TMSVR(${info.svrPort}): ${info.svrConnected ? '연결됨' : '미연결'}`;

      // TMSVR 연결되어 있으면 로봇 상태도 조회
      if (info.svrConnected) {
        try {
          const pos = await client.getPosition();
          text += `\n\n[로봇 위치]\n${pos.data}`;
        } catch {
          text += '\n\n로봇 위치 조회 실패';
        }
      }

      return { content: [{ type: 'text' as const, text }] };
    }
  );

  // ===== 실행 제어 =====

  server.tool(
    'tm_pause',
    '로봇 일시정지',
    {},
    async () => {
      const res = await client.pause();
      return { content: [{ type: 'text' as const, text: `[${res.status}] ${res.message || res.id}` }] };
    }
  );

  server.tool(
    'tm_resume',
    '로봇 재개',
    {},
    async () => {
      const res = await client.resume();
      return { content: [{ type: 'text' as const, text: `[${res.status}] ${res.message || res.id}` }] };
    }
  );

  server.tool(
    'tm_stop',
    '로봇 정지 (Listen Node 종료됨 주의)',
    {},
    async () => {
      const res = await client.stop();
      return { content: [{ type: 'text' as const, text: `[${res.status}] ${res.message || res.id}\n⚠️ Listen Node가 종료되었을 수 있습니다.` }] };
    }
  );

  server.tool(
    'tm_script_exit',
    'Listen Node 탈출 (다음 노드로 진행)',
    {},
    async () => {
      const res = await client.scriptExit();
      return { content: [{ type: 'text' as const, text: `[${res.status}] ${res.message || res.id}` }] };
    }
  );

  // ===== 스크립트 전송 =====

  server.tool(
    'tm_send_script',
    '커스텀 TM Script 전송',
    {
      script: z.string().describe('TM Script 코드'),
    },
    async ({ script }) => {
      const res = await client.sendScript(script);
      return { content: [{ type: 'text' as const, text: `[${res.status}] ${res.message}\nID: ${res.id}\nRaw: ${res.raw}` }] };
    }
  );

  // ===== IO 제어 =====

  server.tool(
    'tm_set_do',
    'Digital Output 설정',
    {
      pin: z.number().describe('DO 핀 번호 (0~7)'),
      state: z.enum(['on', 'off']).describe('on 또는 off'),
    },
    async ({ pin, state }) => {
      const res = await client.setDO(pin, state === 'on');
      return { content: [{ type: 'text' as const, text: `DO${pin} → ${state}: [${res.status}] ${res.message || 'OK'}` }] };
    }
  );

  server.tool(
    'tm_set_ao',
    'Analog Output 설정',
    {
      pin: z.number().describe('AO 핀 번호'),
      value: z.number().describe('출력 값'),
    },
    async ({ pin, value }) => {
      const res = await client.setAO(pin, value);
      return { content: [{ type: 'text' as const, text: `AO${pin} → ${value}: [${res.status}] ${res.message || 'OK'}` }] };
    }
  );

  server.tool(
    'tm_get_io',
    'IO 상태 조회 (DI/DO/AI/AO)',
    {},
    async () => {
      const res = await client.getIO();
      return { content: [{ type: 'text' as const, text: res.data }] };
    }
  );

  // ===== 모션 제어 =====

  server.tool(
    'tm_move_ptp_j',
    'PTP 관절 이동 (Joint)',
    {
      j1: z.number().describe('J1 각도 (도)'),
      j2: z.number().describe('J2 각도 (도)'),
      j3: z.number().describe('J3 각도 (도)'),
      j4: z.number().describe('J4 각도 (도)'),
      j5: z.number().describe('J5 각도 (도)'),
      j6: z.number().describe('J6 각도 (도)'),
      speed: z.number().optional().default(10).describe('속도 (%, 기본 10)'),
      acc: z.number().optional().default(200).describe('가속시간 (ms, 기본 200)'),
    },
    async ({ j1, j2, j3, j4, j5, j6, speed, acc }) => {
      const res = await client.movePtpJ([j1, j2, j3, j4, j5, j6], speed, acc);
      return { content: [{ type: 'text' as const, text: `PTP_J → [${res.status}] ${res.message || '이동 완료'}` }] };
    }
  );

  server.tool(
    'tm_move_ptp_t',
    'PTP 직교 이동 (TCP)',
    {
      x: z.number().describe('X (mm)'),
      y: z.number().describe('Y (mm)'),
      z: z.number().describe('Z (mm)'),
      rx: z.number().describe('Rx (도)'),
      ry: z.number().describe('Ry (도)'),
      rz: z.number().describe('Rz (도)'),
      speed: z.number().optional().default(100).describe('속도 (mm/s, 기본 100)'),
      acc: z.number().optional().default(200).describe('가속시간 (ms, 기본 200)'),
    },
    async ({ x, y, z: pz, rx, ry, rz, speed, acc }) => {
      const res = await client.movePtpT([x, y, pz, rx, ry, rz], speed, acc);
      return { content: [{ type: 'text' as const, text: `PTP_T → [${res.status}] ${res.message || '이동 완료'}` }] };
    }
  );

  server.tool(
    'tm_move_line_j',
    'LINE 관절 이동 (Joint)',
    {
      j1: z.number().describe('J1 각도 (도)'),
      j2: z.number().describe('J2 각도 (도)'),
      j3: z.number().describe('J3 각도 (도)'),
      j4: z.number().describe('J4 각도 (도)'),
      j5: z.number().describe('J5 각도 (도)'),
      j6: z.number().describe('J6 각도 (도)'),
      speed: z.number().optional().default(10).describe('속도 (%, 기본 10)'),
      acc: z.number().optional().default(200).describe('가속시간 (ms, 기본 200)'),
    },
    async ({ j1, j2, j3, j4, j5, j6, speed, acc }) => {
      const res = await client.moveLineJ([j1, j2, j3, j4, j5, j6], speed, acc);
      return { content: [{ type: 'text' as const, text: `LINE_J → [${res.status}] ${res.message || '이동 완료'}` }] };
    }
  );

  server.tool(
    'tm_move_line_t',
    'LINE 직교 이동 (TCP)',
    {
      x: z.number().describe('X (mm)'),
      y: z.number().describe('Y (mm)'),
      z: z.number().describe('Z (mm)'),
      rx: z.number().describe('Rx (도)'),
      ry: z.number().describe('Ry (도)'),
      rz: z.number().describe('Rz (도)'),
      speed: z.number().optional().default(100).describe('속도 (mm/s, 기본 100)'),
      acc: z.number().optional().default(200).describe('가속시간 (ms, 기본 200)'),
    },
    async ({ x, y, z: pz, rx, ry, rz, speed, acc }) => {
      const res = await client.moveLineT([x, y, pz, rx, ry, rz], speed, acc);
      return { content: [{ type: 'text' as const, text: `LINE_T → [${res.status}] ${res.message || '이동 완료'}` }] };
    }
  );

  server.tool(
    'tm_get_pos',
    '현재 위치 조회 (관절 + TCP)',
    {},
    async () => {
      const res = await client.getPosition();
      return { content: [{ type: 'text' as const, text: res.data }] };
    }
  );

  // ===== 변수 제어 =====

  server.tool(
    'tm_set_var',
    '변수 설정',
    {
      name: z.string().describe('변수 이름'),
      value: z.string().describe('변수 값'),
    },
    async ({ name, value }) => {
      const res = await client.setVar(name, value);
      return { content: [{ type: 'text' as const, text: `${name} = ${value}: [${res.status}] ${res.message || 'OK'}` }] };
    }
  );

  server.tool(
    'tm_get_var',
    '변수 조회',
    {
      name: z.string().describe('변수 이름'),
    },
    async ({ name }) => {
      const res = await client.getVar(name);
      return { content: [{ type: 'text' as const, text: `${name}: ${res.data}` }] };
    }
  );

  return server;
}
